const serpData = $input.first().json;
const webhookData = $('Webhook').first().json;

const results = (serpData.organic_results || []).slice(0, 3);

return results.map((r, i) => ({
  json: {
    index: i + 1,
    link: r.link,
    title: r.title,
    snippet: r.snippet || '',
    topic: webhookData.body.topic,
    email: webhookData.body.email
  }
}));

const pageData = $input.first();
const prevData = $('Split In Batches').first().json;

let rawContent = pageData.json.data || pageData.json.body || '';
let cleanText = rawContent
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 3000);

if (!cleanText || cleanText.length < 50) {
  cleanText = prevData.snippet || 'Content could not be retrieved.';
}

return [{
  json: {
    index: prevData.index,
    title: prevData.title,
    link: prevData.link,
    snippet: prevData.snippet,
    content: cleanText,
    topic: prevData.topic,
    email: prevData.email
  }
}];

const raw = $input.first().json.output;


// Strip all markdown symbols
const clean = raw
  .replace(/\*\*/g, '')
  .replace(/###\s*/g, '')
  .replace(/##\s*/g, '')
  .replace(/#\s*/g, '')
  .replace(/---/g, '')
  .replace(/^\s*[-•]\s*/gm, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Split into sections by double newline
const sections = clean.split('\n\n').filter(s => s.trim());

// Build clean HTML
let html = `
<div style="font-family:Arial,sans-serif;max-width:620px;margin:0 auto;color:#222;">

  <h2 style="font-size:20px;border-bottom:2px solid #eee;padding-bottom:10px;">
    Research Report
  </h2>
`;

sections.forEach(section => {
  const lines = section.split('\n').filter(l => l.trim());

  // First line of section = heading if it starts with a number
  const firstLine = lines[0].trim();
  const isHeading = /^\d+\./.test(firstLine);

  if (isHeading) {
    html += `<h3 style="font-size:15px;color:#111;margin-top:24px;margin-bottom:6px;">${firstLine}</h3>`;
    lines.slice(1).forEach(line => {
      html += `<p style="margin:6px 0;line-height:1.8;font-size:14px;color:#333;">${line.trim()}</p>`;
    });
  } else {
    lines.forEach(line => {
      html += `<p style="margin:6px 0;line-height:1.8;font-size:14px;color:#333;">${line.trim()}</p>`;
    });
  }
});

html += `
  <hr style="border:none;border-top:1px solid #eee;margin:28px 0 12px;">
  <p style="color:#aaa;font-size:11px;">Generated by AI Research Assistant · Powered by N8N + OpenAI</p>
</div>`;

return [{ json: { htmlMessage: html } }];
